import React, { useState, useRef, useEffect } from 'react'

interface BackgroundMusicProps {
  audioSrc: string
  autoPlay?: boolean
  loop?: boolean
  volume?: number
}

export const BackgroundMusic: React.FC<BackgroundMusicProps> = ({
  audioSrc,
  autoPlay = true,
  loop = true,
  volume = 0.3
}) => {
  const [isPlaying, setIsPlaying] = useState(false)
  const [showControls, setShowControls] = useState(false)
  const [currentVolume, setCurrentVolume] = useState(volume)
  const [error, setError] = useState<string | null>(null)
  const [isLoaded, setIsLoaded] = useState(false)
  const audioRef = useRef<HTMLAudioElement | null>(null)

  useEffect(() => {
    // Create audio element
    const audio = new Audio()
    audio.src = audioSrc
    audio.loop = loop
    audio.volume = volume
    audio.preload = 'auto'
    
    // Log the path for debugging
    console.log('🎵 Loading audio from:', audioSrc)
    
    // Event listeners for debugging
    audio.addEventListener('loadeddata', () => {
      console.log('✅ Audio loaded successfully')
      setIsLoaded(true)
    })
    
    audio.addEventListener('error', (e) => {
      console.error('❌ Audio load error:', e)
      setError('Failed to load audio file')
    })
    
    audio.addEventListener('canplaythrough', () => {
      console.log('✅ Audio can play through')
      if (autoPlay && !isPlaying) {
        audio.play().catch(err => {
          console.log('🔇 Autoplay blocked:', err)
          setIsPlaying(false)
        })
      }
    })

    audioRef.current = audio

    // Try to autoplay
    if (autoPlay) {
      const playPromise = audio.play()
      if (playPromise !== undefined) {
        playPromise
          .then(() => {
            console.log('▶️ Audio playing')
            setIsPlaying(true)
          })
          .catch((err) => {
            console.log('🔇 Autoplay blocked by browser:', err)
            setIsPlaying(false)
            // Show error but don't break the UI
          })
      }
    }

    return () => {
      audio.pause()
      audio.src = ''
      audio.removeEventListener('loadeddata', () => {})
      audio.removeEventListener('error', () => {})
      audio.removeEventListener('canplaythrough', () => {})
    }
  }, [audioSrc, loop, autoPlay])

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause()
        setIsPlaying(false)
        console.log('⏸️ Paused')
      } else {
        audioRef.current.play()
          .then(() => {
            setIsPlaying(true)
            console.log('▶️ Playing')
          })
          .catch(err => {
            console.error('❌ Play error:', err)
            setError('Cannot play audio')
          })
      }
    }
  }

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVolume = parseFloat(e.target.value)
    setCurrentVolume(newVolume)
    if (audioRef.current) {
      audioRef.current.volume = newVolume
    }
  }

  // Show error state
  if (error) {
    return (
      <div
        style={{
          position: 'fixed',
          bottom: '20px',
          right: '20px',
          zIndex: 9999,
          background: 'rgba(255,68,68,0.15)',
          border: '1px solid #ff4444',
          borderRadius: '12px',
          padding: '10px 16px',
          fontSize: '12px',
          color: '#ff4444'
        }}
      >
        ⚠️ {error}
      </div>
    )
  }

  return (
    <div
      style={{
        position: 'fixed',
        bottom: '20px',
        right: '20px',
        zIndex: 9999,
      }}
      onMouseEnter={() => setShowControls(true)}
      onMouseLeave={() => setShowControls(false)}
    >
      <div
        style={{
          background: 'rgba(10,10,10,0.85)',
          border: '1px solid #c8a20040',
          borderRadius: '12px',
          padding: showControls ? '12px 16px' : '10px',
          backdropFilter: 'blur(10px)',
          transition: 'all 0.3s ease',
          boxShadow: '0 4px 20px rgba(0,0,0,0.5)',
          minWidth: showControls ? '200px' : 'auto',
          display: 'flex',
          alignItems: 'center',
          gap: '10px'
        }}
      >
        <button
          onClick={togglePlay}
          style={{
            background: isPlaying ? '#c8a20020' : '#c8a200',
            border: 'none',
            borderRadius: '50%',
            width: '36px',
            height: '36px',
            cursor: 'pointer',
            fontSize: '18px',
            color: isPlaying ? '#c8a200' : '#0a0a0a',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            transition: 'all 0.3s',
            flexShrink: 0
          }}
        >
          {isPlaying ? '⏸' : '▶️'}
        </button>

        {showControls && (
          <>
            <div style={{ flex: 1 }}>
              <div style={{ 
                fontSize: '10px', 
                color: '#888', 
                marginBottom: '2px',
                whiteSpace: 'nowrap'
              }}>
                {isLoaded ? '🎵 Background Music' : '⏳ Loading...'}
              </div>
              <input
                type="range"
                min="0"
                max="1"
                step="0.01"
                value={currentVolume}
                onChange={handleVolumeChange}
                style={{
                  width: '100%',
                  height: '4px',
                  background: 'linear-gradient(to right, #c8a200, #FFD700)',
                  borderRadius: '2px',
                  outline: 'none',
                  cursor: 'pointer',
                  WebkitAppearance: 'none'
                }}
              />
            </div>
            <span style={{ color: '#666', fontSize: '10px' }}>
              {Math.round(currentVolume * 100)}%
            </span>
          </>
        )}
      </div>
    </div>
  )
}
